property_tests.invariant_check:
routes = echo_app.Routes()
for route in routes:
    assert NOT contains(route.Path, '/workspaces')
// Positive assertion: all team routes are present
team_routes = [r for r in routes if contains(r.Path, '/api/v1/teams')]
assert len(team_routes) >= 8 // at minimum the 8 required team endpoints

for each (method, path, body) in team_endpoint_calls:
    resp = http_request(method, path, body)
    if resp.status_code in [200, 201]:
        json_body = parse_json(resp.body)
        all_keys = flatten_json_keys(json_body)
        assert 'workspace_id' NOT in all_keys
        if carries_org_id(json_body):
            assert 'team_id' in all_keys

edge_case_tests.assertion_pseudocode:
// The CI step inverts grep exit codes: grep succeeds (exits 0) if it FINDS a match → CI step FAILS
result = run_command('grep -E "workspaces|workspace_members|workspace_id" internal/db/db.go')
assert result.exit_code != 0 // grep finds NO matches → exit code 1 → CI passes
// Negative test (simulating broken state):
bad_ddl = 'CREATE TABLE workspaces (id TEXT)'
assert grep(bad_ddl, r'workspaces') exits 0 // would trigger CI failure
